import{_ as t,o as r,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const b=JSON.parse('{"title":"拐棍糖","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/拐棍糖.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/拐棍糖.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/拐棍糖.md"};function p(l,a,_,i,c,h){return r(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"拐棍糖",tabindex:"-1"},[s("拐棍糖 "),e("a",{class:"header-anchor",href:"#拐棍糖","aria-label":'Permalink to "拐棍糖"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌032")])])],-1),o('<h1 id="拐棍糖-1" tabindex="-1">拐棍糖 <a class="header-anchor" href="#拐棍糖-1" aria-label="Permalink to &quot;拐棍糖&quot;">​</a></h1><p>拐棍糖</p><p>D+1000</p><p>武器伤害6L，武器体积3<br> 武器类型：棍</p><p>拐棍糖是一种具有标志性“J”形或手杖状的硬质糖果。最经典的是红白螺旋条纹相间，带有清凉的薄荷口味。它质地坚硬光滑，需要吮吸或含化。作为圣诞节的重要象征，其形状常被联系到牧羊人的拐杖或耶稣（J），红白配色则蕴含宗教意义。它既是节日里受欢迎的甜食，也是常用的圣诞树装饰和节日礼物。</p><p>当你使用这根拐棍糖击中敌人时，你可以轻轻敲醒对方沉睡的孩童心思，他使用意志豁免对抗伤害出目，若失败，则他在该场景中会避开你作为攻击目标（除非你已经是最后的目标），这是一个D级心灵来源的胁迫效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=t(d,[["render",p]]);export{b as __pageData,m as default};
